// https://drafts.csswg.org/cssom-view/#scrollend-event
[Exposed=Window]
interface ScrollendEvent : Event {
  [Throws] constructor(DOMString type, optional ScrollendEventInit eventInitDict = {});
};

dictionary ScrollendEventInit : EventInit {
};

