use crate::dom::window::Window;
use crate::script_runtime::CanGc;
use stylo_atoms::Atom;

#[dom_struct]
pub(crate) struct ScrollendEvent {
    event: Event,
}

impl ScrollendEvent {
    fn new_inherited() -> ScrollendEvent {
        ScrollendEvent {
            event: Event::new_inherited(),
        }
    }

    pub(crate) fn new(
        window: &Window,
        type_: Atom,
        init: &ScrollendEventInit,
        can_gc: CanGc,
    ) -> DomRoot<ScrollendEvent> {
        Self::new_with_proto(window, None, type_, init, can_gc)
    }

    fn new_with_proto(
        window: &Window,
        proto: Option<HandleObject>,
        type_: Atom,
        init: &ScrollendEventInit,
        can_gc: CanGc,
    ) -> DomRoot<ScrollendEvent> {
        let ev = reflect_dom_object_with_proto(
            Box::new(ScrollendEvent::new_inherited()),
            window,
            proto,
            can_gc,
        );
        {
            let event = ev.upcast::<Event>();
            event.init_event(type_, init.parent.bubbles, init.parent.cancelable);
        }
        ev
    }
}

impl ScrollendEventMethods<crate::DomTypeHolder> for ScrollendEvent {
    /// <https://drafts.csswg.org/cssom-view/#dom-scrollendevent-constructor>
    fn Constructor(
        window: &Window,
        proto: Option<HandleObject>,
        can_gc: CanGc,
        type_: DOMString,
        init: &ScrollendEventInit,
    ) -> DomRoot<ScrollendEvent> {
        ScrollendEvent::new_with_proto(window, proto, Atom::from(type_), init, can_gc)
    }

    /// <https://dom.spec.whatwg.org/#dom-event-istrusted>
    fn IsTrusted(&self) -> bool {
        self.upcast::<Event>().IsTrusted()
    }
}

